// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {PrecompileConsumer} from "./utils/PrecompileConsumer.sol";

// ────────────────────────────────────────────────────────────────────────────
//  AIBountyJudgePro — Enhanced AI-powered bounty judge on Ritual Chain
//  Features: Multi-submission bounties, AI adjudication, on-chain settlement
// ────────────────────────────────────────────────────────────────────────────

interface IRitualWallet {
    function deposit(uint256 lockDuration) external payable;
    function depositFor(address user, uint256 lockDuration) external payable;
    function withdraw(uint256 amount) external;
    function balanceOf(address) external view returns (uint256);
    function lockUntil(address) external view returns (uint256);
}

contract AIBountyJudgePro is PrecompileConsumer {

    // ── Constants ──────────────────────────────────────────────────────────
    uint256 public constant MAX_SUBMISSIONS   = 15;       // increased from 10
    uint256 public constant MAX_ANSWER_LENGTH = 2_000;
    string  public constant CONTRACT_VERSION  = "1.0.0";

    // ── Ritual Wallet (executor/precompile callback address) ───────────────
    IRitualWallet public wallet =
        IRitualWallet(0xB42e435c4252A5a2E7440e37B609F00c61a0c91B);

    // ── State ──────────────────────────────────────────────────────────────
    uint256 public nextBountyId = 1;
    address public deployer;

    struct Submission {
        address submitter;
        string  answer;
        uint256 submittedAt;
    }

    struct Bounty {
        address       owner;
        string        title;
        string        rubric;
        string        category;      // NEW: category tag (e.g. "DeFi", "Security")
        uint256       reward;
        uint256       deadline;
        bool          judged;
        bool          finalized;
        bytes         aiReview;
        uint256       winnerIndex;
        Submission[]  submissions;
    }

    struct ConvoHistory {
        string storageType;
        string path;
        string secretsName;
    }

    mapping(uint256 => Bounty) public bounties;

    // ── Events ─────────────────────────────────────────────────────────────
    event BountyCreated(
        uint256 indexed bountyId,
        address indexed owner,
        string  title,
        string  category,
        uint256 reward,
        uint256 deadline
    );

    event AnswerSubmitted(
        uint256 indexed bountyId,
        uint256 indexed submissionIndex,
        address indexed submitter,
        uint256 timestamp
    );

    event AllAnswersJudged(
        uint256 indexed bountyId,
        bytes   aiReview,
        uint256 timestamp
    );

    event WinnerFinalized(
        uint256 indexed bountyId,
        uint256 indexed winnerIndex,
        address indexed winner,
        uint256 reward,
        uint256 timestamp
    );

    // ── Modifiers ──────────────────────────────────────────────────────────
    modifier onlyOwner(uint256 bountyId) {
        require(msg.sender == bounties[bountyId].owner, "not bounty owner");
        _;
    }

    modifier bountyExists(uint256 bountyId) {
        require(bounties[bountyId].owner != address(0), "bounty not found");
        _;
    }

    // ── Constructor ────────────────────────────────────────────────────────
    constructor() {
        deployer = msg.sender;
    }

    // ── Core Functions ─────────────────────────────────────────────────────

    /**
     * @notice Create a new bounty with an optional category tag.
     * @param title    Human-readable bounty title.
     * @param rubric   AI judging criteria / rubric.
     * @param category Optional category label (e.g. "DeFi", "Security", "NFT").
     * @param deadline Unix timestamp after which submissions close.
     */
    function createBounty(
        string calldata title,
        string calldata rubric,
        string calldata category,
        uint256 deadline
    ) external payable returns (uint256 bountyId) {
        require(msg.value > 0, "reward required");

        bountyId = nextBountyId++;

        Bounty storage bounty = bounties[bountyId];
        bounty.owner       = msg.sender;
        bounty.title       = title;
        bounty.rubric      = rubric;
        bounty.category    = category;
        bounty.reward      = msg.value;
        bounty.deadline    = deadline;
        bounty.winnerIndex = type(uint256).max;

        emit BountyCreated(bountyId, msg.sender, title, category, msg.value, deadline);
    }

    /**
     * @notice Submit an answer to an open bounty.
     * @param bountyId Target bounty.
     * @param answer   Plaintext answer (max 2000 chars).
     */
    function submitAnswer(
        uint256 bountyId,
        string calldata answer
    ) external bountyExists(bountyId) {
        Bounty storage bounty = bounties[bountyId];

        require(!bounty.judged,    "already judged");
        require(!bounty.finalized, "already finalized");
        require(
            bounty.submissions.length < MAX_SUBMISSIONS,
            "submission cap reached"
        );
        require(bytes(answer).length <= MAX_ANSWER_LENGTH, "answer too long");
        require(bytes(answer).length > 0, "answer cannot be empty");

        uint256 idx = bounty.submissions.length;
        bounty.submissions.push(
            Submission({
                submitter:   msg.sender,
                answer:      answer,
                submittedAt: block.timestamp
            })
        );

        emit AnswerSubmitted(bountyId, idx, msg.sender, block.timestamp);
    }

    /**
     * @notice Trigger Ritual AI to judge all submissions for a bounty.
     *         Only the bounty owner may call this.
     * @param bountyId Target bounty.
     * @param llmInput ABI-encoded Ritual LLM precompile request payload.
     */
    function judgeAll(
        uint256 bountyId,
        bytes calldata llmInput
    ) external bountyExists(bountyId) onlyOwner(bountyId) {
        Bounty storage bounty = bounties[bountyId];

        require(!bounty.judged,    "already judged");
        require(!bounty.finalized, "already finalized");
        require(bounty.submissions.length > 0, "no submissions to judge");

        bytes memory output = _executePrecompile(
            LLM_INFERENCE_PRECOMPILE,
            llmInput
        );

        (
            bool   hasError,
            bytes  memory completionData,
            ,
            string memory errorMessage,

        ) = abi.decode(output, (bool, bytes, bytes, string, ConvoHistory));

        require(!hasError, errorMessage);

        bounty.judged   = true;
        bounty.aiReview = completionData;

        emit AllAnswersJudged(bountyId, completionData, block.timestamp);
    }

    /**
     * @notice Finalize the bounty: pick a winner and transfer the reward.
     * @param bountyId    Target bounty.
     * @param winnerIndex Index into the submissions array.
     */
    function finalizeWinner(
        uint256 bountyId,
        uint256 winnerIndex
    ) external bountyExists(bountyId) onlyOwner(bountyId) {
        Bounty storage bounty = bounties[bountyId];

        require(bounty.judged,     "not judged yet");
        require(!bounty.finalized, "already finalized");
        require(winnerIndex < bounty.submissions.length, "invalid index");

        bounty.finalized   = true;
        bounty.winnerIndex = winnerIndex;

        address winner = bounty.submissions[winnerIndex].submitter;
        uint256 reward = bounty.reward;
        bounty.reward  = 0;

        (bool ok, ) = payable(winner).call{value: reward}("");
        require(ok, "payment failed");

        emit WinnerFinalized(bountyId, winnerIndex, winner, reward, block.timestamp);
    }

    // ── View Functions ─────────────────────────────────────────────────────

    function getBounty(uint256 bountyId)
        external
        view
        bountyExists(bountyId)
        returns (
            address owner,
            string  memory title,
            string  memory rubric,
            string  memory category,
            uint256 reward,
            uint256 deadline,
            bool    judged,
            bool    finalized,
            uint256 submissionCount,
            uint256 winnerIndex,
            bytes   memory aiReview
        )
    {
        Bounty storage bounty = bounties[bountyId];
        return (
            bounty.owner,
            bounty.title,
            bounty.rubric,
            bounty.category,
            bounty.reward,
            bounty.deadline,
            bounty.judged,
            bounty.finalized,
            bounty.submissions.length,
            bounty.winnerIndex,
            bounty.aiReview
        );
    }

    function getSubmission(
        uint256 bountyId,
        uint256 index
    )
        external
        view
        bountyExists(bountyId)
        returns (
            address submitter,
            string  memory answer,
            uint256 submittedAt
        )
    {
        Bounty storage bounty = bounties[bountyId];
        require(index < bounty.submissions.length, "invalid index");

        Submission storage sub = bounty.submissions[index];
        return (sub.submitter, sub.answer, sub.submittedAt);
    }

    /**
     * @notice Returns basic contract metadata for UI display.
     */
    function getContractInfo()
        external
        view
        returns (
            string  memory version,
            address deployerAddr,
            uint256 totalBounties
        )
    {
        return (CONTRACT_VERSION, deployer, nextBountyId - 1);
    }
}

